CREATE VIEW `ads_sr_market_operation_exp_report_di_view` (`dt` COMMENT "日期", `operation_user` COMMENT "操作用户", `position_id` COMMENT "资源位ID", `position_type` COMMENT "资源位类型 1：banner，2：悬浮窗，3：弹窗，4：闪屏，5：阅读页触达，8：章末推送，9：阅读器返回推，10：串书，11：TAB推荐", `position_name` COMMENT "资源位名称", `rules_type` COMMENT "显示规则类型 1 每日首次推送（只推一次）、2 间隔N章 、 3 立即推送", `app_type` COMMENT "应用类型 1：正式，2：测试", `strategy_type` COMMENT "策略类型 0：实验策略，1：固化策略", `sorted` COMMENT "排序", `actity_id` COMMENT "活动ID", `actity_type` COMMENT "活动类型 1：充值档位推荐，2：VIP档位推荐,3:签到卡档位推荐,4:自定义活动,5:组合活动,6:推剧(剧目单),7:推剧(指定短剧)", `actity_time` COMMENT "活动时间", `start_time` COMMENT "活动开始时间", `end_time` COMMENT "活动结束时间", `action_id` COMMENT "策略ID", `action_name` COMMENT "策略名称", `statu` COMMENT "状态 1：开启，2：关闭", `exposure_rule` COMMENT "过曝规则", `create_time` COMMENT "活动策略创建时间", `jgroup_ids` COMMENT "极光人群包", `tag_group_ids` COMMENT "TAG人群包", `etl_time` COMMENT "etl清洗时间")
COMMENT "海阅-运营实验报表-关联运营ID" AS SELECT `dwd`.`dwd_sr_market_operation_exp_report_di`.`dt`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`operation_user`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`position_id`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`position_type`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`position_name`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`rules_type`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`app_type`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`strategy_type`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`sorted`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`actity_id`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`actity_type`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`actity_time`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`start_time`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`end_time`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`action_id`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`action_name`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`statu`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`exposure_rule`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`create_time`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`jgroup_ids`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`tag_group_ids`, `dwd`.`dwd_sr_market_operation_exp_report_di`.`etl_time`
FROM `dwd`.`dwd_sr_market_operation_exp_report_di`;